const fs = require('fs');
const config = JSON.parse(fs.readFileSync('/home/node/config/scrapers.json', 'utf8'));
const resourceSources = config.sources.filter(s => s.category === 'resource' && s.enabled !== false);
return resourceSources.map(s => ({ json: s }));

// Parse HTML based on site selector and extract news items
const source = $('Loop Over Sources').item.json;
const html = $input.item.json.data || $input.item.json.body || $input.item.json;
const name = source.name;
const baseUrl = source.base_url || '';
const maxItems = source.max_items || 10;

let items = [];

if (name === 'dlut_scidep') {
  // ul.tz-ul > li: date in tz-ul-date, title in tz-ul-tt, href in a
  const liRegex = /<li[^>]*>\s*<a[^>]+href=["']([^"']+)["'][^>]*>[\s\S]*?<div[^>]*class=["'][^"']*tz-ul-date[^"']*["'][^>]*>(.*?)<\/div>[\s\S]*?<div[^>]*class=["'][^"']*tz-ul-tt[^"']*["'][^>]*>([^<]+)<\/div>[\s\S]*?<\/a>\s*<\/li>/gi;
  let m;
  while ((m = liRegex.exec(html)) !== null && items.length < maxItems) {
    const href = m[1];
    const dateRaw = m[2].replace(/<[^>]+>/g, '').trim();
    const title = m[3].trim();
    const url = href.startsWith('http') ? href : baseUrl + href;
    items.push({ title, date: dateRaw, url });
  }
} else if (name === 'dlut_sche') {
  // div.sublist ul > li: a[href] + text, span.date
  const liRegex = /<li[^>]*style[^>]*>\s*<a[^>]+href=["']([^"']+)["'][^>]*>([^<]+)<\/a>\s*<span[^>]*class=["'][^"']*date[^"']*["'][^>]*>([^<]+)<\/span>/gi;
  let m;
  while ((m = liRegex.exec(html)) !== null && items.length < maxItems) {
    const href = m[1];
    const title = m[2].trim();
    const date = m[3].trim();
    const url = href.startsWith('http') ? href : baseUrl + href;
    items.push({ title, date, url });
  }
} else if (name === 'dlut_futureschool') {
  // div.list ul > li: a[href+title], div.time, div.name
  const liRegex = /<li[^>]*>[\s\S]*?<a[^>]+href=["']([^"']+)["'][^>]*>[\s\S]*?<div[^>]*class=["'][^"']*time[^"']*["'][^>]*>([^<]+)<\/div>[\s\S]*?<div[^>]*class=["'][^"']*name[^"']*["'][^>]*>([^<]+)<\/div>[\s\S]*?<\/a>[\s\S]*?<\/li>/gi;
  let m;
  while ((m = liRegex.exec(html)) !== null && items.length < maxItems) {
    const href = m[1];
    const date = m[2].trim();
    const title = m[3].trim();
    const url = href.startsWith('http') ? href : baseUrl + href;
    items.push({ title, date, url });
  }
} else if (name === 'dlut_news_academic') {
  // ul.nylistn > li.bg-mask: time span + text content
  const liRegex = /<li[^>]*class=["'][^"']*bg-mask[^"']*["'][^>]*>[\s\S]*?<time[^>]*><span>(\d+)<\/span>([^<]+)<\/time>[\s\S]*?<a[^>]+href=["']([^"']+)["'][^>]*>([\s\S]*?)<\/a>[\s\S]*?<\/li>/gi;
  let m;
  while ((m = liRegex.exec(html)) !== null && items.length < maxItems) {
    const day = m[1];
    const yearMonth = m[2].trim();
    const href = m[3];
    const rawText = m[4].replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim();
    // Extract title - often starts with 【...】 prefix
    const title = rawText.substring(0, 80);
    const date = yearMonth + '-' + day.padStart(2, '0');
    const url = href.startsWith('http') ? href : baseUrl + href;
    items.push({ title, date, url });
  }
}

if (items.length === 0) {
  return [{ json: { source: source, items: [], hasItems: false } }];
}

return [{ json: { source: source, items: items, hasItems: true } }];

const { source, items } = $input.item.json;
const config = JSON.parse(require('fs').readFileSync('/home/node/config/scrapers.json', 'utf8'));
const promptTemplate = config.prompt_templates.university_news;

const itemsText = items.map((item, i) => 
  `${i+1}. [${item.date}] ${item.title}\n   链接：${item.url}`
).join('\n');

const sourceLabel = `【${source.display_name}】`;
const prompt = promptTemplate.replace('{items}', sourceLabel + '\n' + itemsText);

return [{ json: { source, items, prompt } }];

const prevData = $('Build Prompt').item.json;
const { source, items } = prevData;
const aiResponse = $input.item.json;
const summary = aiResponse.choices?.[0]?.message?.content || '';

const date = new Date().toLocaleDateString('zh-CN', { timeZone: 'Asia/Shanghai' }).replace(/\//g, '-');
const isoDate = new Date().toLocaleDateString('en-CA', { timeZone: 'Asia/Shanghai' });

const content = `# ${source.display_name} — ${isoDate}\n\n${summary}\n\n---\n*共 ${items.length} 条，来源：${source.url}*\n`;

const fileName = `${source.name}_${isoDate}.md`;
const filePath = `/home/node/workspace/briefings/resource/${fileName}`;

return [{ json: { filePath, content, sourceName: source.display_name } }];

const { filePath, content } = $input.item.json;
const fs = require('fs');
const dir = filePath.substring(0, filePath.lastIndexOf('/'));
if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });
fs.writeFileSync(filePath, content, 'utf8');
return [{ json: { saved: true, filePath } }];
